#include<bits/stdc++.h>
using namespace std;
set<string> t;
int n,m,a[510][510];
int l1[1000000],l2[1000000],r1[1000000],r2[1000000],dx[4]={1,-1,0,0},dy[4]={0,0,1,-1};
bool v[510][510];
void dfs(int x,int y,int c,int f){
	for(int i=0;i<4;i++){
		int nx=x+dx[i],ny=y+dy[i];
		if(nx<1||ny<1||nx>n||ny>m||v[nx][ny]||a[nx][ny]!=f)continue;
		v[nx][ny]=1,a[nx][ny]=c;
		l1[c]=min(l1[c],nx);
		l2[c]=min(l2[c],ny);
		r1[c]=max(r1[c],nx);
		r2[c]=max(r2[c],ny);
		dfs(nx,ny,c,f);
	}
}
int main(){
	int x=0;
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cin>>a[i][j];
		}
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			if(v[i][j])continue;
			l1[++x]=r1[x]=i,l2[x]=r2[x]=j;
			dfs(i,j,x,a[i][j]);
			a[i][j]=x;
		}
	}
//	for(int i=1;i<=n;i++){
//		for(int j=1;j<=m;j++){
//			cout<<a[i][j]<<" "; 
//		}
//		cout<<"\n";
//	}
	for(int i=1;i<=x;i++){
		string s;
		for(int j=l1[i];j<=r1[i];j++){
			for(int k=l2[i];k<=r2[i];k++){
				if(a[j][k]==i)s+='1';
				else s+='0';
			}
			s+=' ';
		}
		if(!t.count(s))t.insert(s);
	}
//	for(auto y:t)cout<<y<<"\n";
	cout<<t.size()+1;
	return 0;
}
